// ==================== RENDER CARS ====================
let currentCarIndex = 0;
let filteredCars = [...cars];
let selectedCar = null;

function renderCars(list) {
  const grid = document.getElementById('carsGrid');
  grid.innerHTML = '';
  list.forEach((car, i) => {
    const card = document.createElement('div');
    card.className = 'car-card' + (car.featured ? ' featured' : '') + ' reveal';
    card.style.transitionDelay = (i * 0.05) + 's';
    card.innerHTML = `
      <div style="width:100%;height:100%;position:relative;overflow:hidden;">
        <img src="${carImages[i % carImages.length]}" alt="${car.brand} ${car.model}" class="car-image" style="width:100%;height:100%;object-fit:cover;object-position:center;">
      </div>
      <div class="car-card-content">
        <div class="car-quick-specs">
          <div class="quick-spec"><span>${car.quick.km}</span>Quilometragem</div>
          <div class="quick-spec"><span>${car.quick.motor}</span>Motor</div>
          <div class="quick-spec"><span>${car.quick.cv}</span>Potência</div>
        </div>
        <div class="car-brand">${car.brand}</div>
        <div class="car-name">${car.model}</div>
        <div class="car-price-row">
          <div class="car-price">
            <small>A partir de</small>
            <strong>${car.price}</strong>
          </div>
          <span class="car-tag">${car.tag}</span>
        </div>
      </div>
    `;
    card.addEventListener('click', () => openCarModal(i, list));
    grid.appendChild(card);
  });
  // Re-trigger reveal
  setTimeout(() => observeReveal(), 100);
}

function filterCars(cat, btn) {
  document.querySelectorAll('.filter-btn').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  filteredCars = cat === 'all' ? [...cars] : cars.filter(c => c.category === cat);
  renderCars(filteredCars);
}

// ==================== MODAL ====================
function openCarModal(idx, list) {
  list = list || filteredCars;
  currentCarIndex = idx;
  selectedCar = list[idx];
  populateModal(selectedCar, idx);
  document.getElementById('carModal').classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeModal() {
  document.getElementById('carModal').classList.remove('open');
  document.body.style.overflow = '';
}

function prevCar() {
  currentCarIndex = (currentCarIndex - 1 + filteredCars.length) % filteredCars.length;
  selectedCar = filteredCars[currentCarIndex];
  populateModal(selectedCar, currentCarIndex);
}

function nextCar() {
  currentCarIndex = (currentCarIndex + 1) % filteredCars.length;
  selectedCar = filteredCars[currentCarIndex];
  populateModal(selectedCar, currentCarIndex);
}

function populateModal(car, idx) {
  document.getElementById('mBrand').textContent = car.brand + ' · ' + car.year;
  document.getElementById('mName').textContent = car.model;
  document.getElementById('mPrice').textContent = car.price;

  // Real image visual
  const visual = document.getElementById('modalCarVisual');
  visual.style.background = '#0a0a0a';
  visual.innerHTML = `<img src="${carImages[idx % carImages.length]}" alt="${car.brand} ${car.model}" style="width:100%;height:100%;object-fit:cover;object-position:center;filter:brightness(0.85);transition:transform 0.8s cubic-bezier(0.23,1,0.32,1);">`;

  // Specs
  const specsEl = document.getElementById('mSpecs');
  specsEl.innerHTML = car.specs.map(([k,v]) => `
    <div class="spec-row"><span class="spec-key">${k}</span><span class="spec-val">${v}</span></div>
  `).join('');

  // Equips
  const equipsEl = document.getElementById('mEquips');
  equipsEl.innerHTML = car.equips.map(e => `<span class="equip-tag">${e}</span>`).join('');

  // Commercial
  const commEl = document.getElementById('mCommercial');
  commEl.innerHTML = car.commercial.map(([k,v]) => `
    <div class="spec-row"><span class="spec-key">${k}</span><span class="spec-val" style="color:var(--purple-neon)">${v}</span></div>
  `).join('');
}

function openFinancingFromModal() {
  closeModal();
  openFormModal(selectedCar ? selectedCar.brand + ' ' + selectedCar.model : null);
}

function whatsappCar() {
  const msg = selectedCar ? `Olá! Tenho interesse no ${selectedCar.brand} ${selectedCar.model} ${selectedCar.year} — ${selectedCar.price}. Poderia me passar mais informações?` : `Olá! Gostaria de mais informações sobre os veículos disponíveis.`;
  window.open('https://wa.me/5511999990000?text=' + encodeURIComponent(msg), '_blank');
}

